"use client"
import React, { useState } from 'react'
import Button from './ui/Button'
import AddPostModal from './AddPostModal'
import { usePosts } from './PostsProvider'

export default function TopBar({ sidebarOpen, setSidebarOpen }: { sidebarOpen?: boolean; setSidebarOpen?: (v: boolean) => void }) {
  const [open, setOpen] = useState(false)
  const [toast, setToast] = useState<string | null>(null)
  const { searchText, setSearchText, sortOption, setSortOption } = usePosts()

  function handleImported() {
    setToast('Post imported')
    setTimeout(() => setToast(null), 3000)
  }

  return (
    <div className="flex items-center justify-between px-4 md:px-6 py-3 gap-4">
      <div className="flex items-center gap-3">
        {/* Mobile hamburger */}
        <button
          className="md:hidden p-2 rounded hover:bg-slate-100"
          onClick={() => setSidebarOpen && setSidebarOpen(!sidebarOpen)}
          aria-label="Toggle sidebar"
        >
          <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24" xmlns="http://www.w3.org/2000/svg"><path strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" d="M4 6h16M4 12h16M4 18h16"></path></svg>
        </button>

        <div className="text-lg font-semibold">{(function(){
          const { activeCategoryId, activeCollectionId } = (window as any).__usePostsSnapshot || {}
          if (activeCategoryId) return `Category: ${activeCategoryId.replace('c-','')}`
          if (activeCollectionId) return `Collection: ${activeCollectionId.replace('col-','')}`
          return 'All Posts'
        })()}</div>

        <div className="hidden sm:block">
          <input
            placeholder="Search captions, transcripts, notes..."
            value={searchText}
            onChange={(e) => setSearchText(e.target.value)}
            className="border rounded px-3 py-1 text-sm w-36 sm:w-64"
          />
        </div>
        <select className="hidden md:block border rounded px-2 py-1 text-sm" value={sortOption} onChange={(e) => setSortOption(e.target.value as any)}>
          <option value="newest">Newest saved</option>
          <option value="oldest">Oldest saved</option>
          <option value="recently-edited">Recently edited</option>
        </select>
      </div>

      <div className="flex items-center gap-3">
        <Button onClick={() => setOpen(true)} aria-label="open-add-post">+ Add Post</Button>
        <div className="w-8 h-8 bg-slate-200 rounded-full" />
      </div>

      <AddPostModal open={open} onClose={() => setOpen(false)} onImported={handleImported as any} />

      {toast && (
        <div className="fixed right-4 bottom-4 bg-slate-900 text-white px-4 py-2 rounded shadow">{toast}</div>
      )}
    </div>
  )
}
